package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsNull() throws Exception {
        // Use withCommentMarker((Character) null) to set commentMarker to null
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker((Character) null);

        assertFalse(format.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsSet() throws Exception {
        // Use withCommentMarker('#') to set commentMarker to '#'
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');

        assertTrue(format.isCommentMarkerSet());
    }
}
